let mchainn = function(tokens,nexts,n)
{
	let prevs = new Array(n);
	var prev = "";
	var i,k;

	for( i=0; i<n; i++ ) {
		prevs[i] = tokens[i];
		if( prev != "" ) prev += ",";
		prev += prevs[i];
	}

	for( i=n; i<tokens.length; i++ ) {

		if( !(prev in nexts) ) nexts[prev] = {};
		if( !(tokens[i] in nexts[prev]) ) nexts[prev][tokens[i]] = 1;
		else nexts[prev][tokens[i]]++;
		
		prev = "";
		for( k=0; k<n-1; k++ ) {
			prevs[k] = prevs[k+1];
			if( prev != "" ) prev += ",";
			prev += prevs[k];
		}
		prevs[k] = tokens[i];
		if( prev != "" ) prev += ",";
		prev += prevs[k];
	}

	for( i in nexts ) {
		let arr = nexts[i];
		let sum=0;
		for( k in arr ) {
			sum += arr[k];
		}
		for( k in arr ) {
			arr[k] = arr[k] / sum;
		}
	}

	return nexts;
}
