let setMode = 8;
let genWords = 70;

let genp = function(buf) {
	var i,k;
	var a,b;
	var u,v;

	if( buf[0] == "/" || buf[0] == '-' ) {
		let ctype = buf[0];

		let args = buf.split(" ");
		let cmd = args.shift().substring(1);

		if( ctype == '/' ) {
			setMode = parseInt(cmd);
		} else if( ctype == '-' ) {
			genWords = parseInt(cmd);
		}
		buf = args.join(" ");
	}
	if( buf == "" ) buf = "The";

	let ws = [], ts = [], ps = [];
	let bufs = buf.split(" ");
	for( var i=0; i<bufs.length; i++ ) {
		ws.push(bufs[i]);
	}


	for( i=0; i<genWords; i++ ) {
		var w = {}, z = {};
		ts=[];
		ps=[];
		for( k=0; k<ws.length && k<setMode; k++ ) {
			[a,b] = toTokens(ws[k]);
			ts.push( a );
			ps.push( b );
//			if( i < 5 ) console.log("T",ts);
			[v,u] = nextwordpn(ts,ps);
			for( var j in v ) {
				w[j] = v[j] * 1/Math.pow(4,ws.length-k);
			}
			for( var j in u ) {
				z[j] = u[j] * 1/Math.pow(4,ws.length-k);
			}
		}
		w = nextofp(w,z);
		if( typeof w == 'undefined' ) {
			w = "a";
		}

		for( k=0; k+1<ws.length && k+1<setMode; k++ ) {
			ws[k] = ws[k+1];
		}
		ws[k] = w;

		for( k=0; k+1<ps.length && k+1<setMode; k++ ) {
			ps[k] = ps[k+1];
		}
		ps[k] = parts[w];

		buf = joinWord(buf,w);
	}
	return buf;
}

