function nextof( nest )
{
	var t = 0;
	for( var i in nest ) {
		t += nest[i];
	}
	var x = Math.random()*t;
	for( var i in nest ) {
		x -= nest[i];
		if( x <= 0 ) return dict[i];
	}
	var k = Object.keys(nest);
	return dict[ k[ k.length - 1 ] ];
}


